external_knowledge:
- 'big spenders' refers to companies with total payments exceeding $1000.0; 
- 'certain type' refers to market participants with a participant_type_id of 1; 
- 'certain role' refers to market participants with a participant_role_id of 1.

sql:
SELECT participant_id, company_name, company_address, company_phone
FROM market_participants
WHERE participant_id = 0;

SELECT process_id, transaction_id, balancing_date, balancing_status
FROM balancing_processes
WHERE balancing_status = 'pending';

SELECT company_name, company_phone
FROM market_participants
WHERE company_name LIKE '%E.ON%';

SELECT energy_type, COUNT(*) AS transaction_count
FROM energy_transactions
GROUP BY energy_type;

SELECT SUM(total_cost) AS total_pending_cost
FROM energy_transactions
WHERE transaction_status = 'pending';

SELECT total_cost
FROM energy_transactions
WHERE transaction_status = 'settled';

SELECT description
FROM market_participant_types
WHERE participant_type_name = 'Generation Company';

SELECT SUM(total_cost) AS total_transaction_cost
FROM energy_transactions
WHERE participant_id = 1;

SELECT description
FROM market_participant_roles
WHERE participant_role_name = 'Buyer';

SELECT company_name, COUNT(company_email) AS email_count
FROM market_participants
GROUP BY company_name;

SELECT dispute_status, COUNT(*) AS dispute_count
FROM disputes
GROUP BY dispute_status;
